 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 5	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { Button, ButtonVariant, Popover } from '@patternfly/react-core';
 8	import { HelpIcon } from '@patternfly/react-icons';
 9	import styles from '@patternfly/react-styles/css/components/Form/form';
10	
11	import './NetworkSelectHelperPopover.scss';
12	
13	const NetworkSelectHelperPopover: FC = () => {
14	  const { t } = useKubevirtTranslation();
15	  return (
16	    <Popover
17	      bodyContent={
18	        <>
19	          <Trans t={t}>
20	            <div>
21	              <b>Bridge binding</b>: Connects the VirtualMachine to the selected network, which is
22	              ideal for L2 devices.
23	            </div>
24	            <div className="NetworkSelectPopoverSriovLabel">
25	              <b>SR-IOV binding</b>: Attaches a virtual function network device to the
26	              VirtualMachine for high performance.
27	            </div>
28	          </Trans>
29	          <ExternalLink href={documentationURL.VIRT_SECONDARY_NETWORK} text={t('Learn more')} />
30	        </>
31	      }
32	      headerContent={t('Network binding types')}
33	    >
34	      <Button className={styles.formGroupLabelHelp} variant={ButtonVariant.plain}>
35	        <HelpIcon />
36	      </Button>
37	    </Popover>
38	  );
39	};
40	export default NetworkSelectHelperPopover;

